export const scalePixelArt = (image: string[], scale: number): string[] => {
  const result: string[] = [];
  for (const row of image) {
    const scaledRow = row
      .split("")
      .map((c) => c.repeat(scale))
      .join("");
    for (let i = 0; i < scale; i++) {
      result.push(scaledRow);
    }
  }
  return result;
};

